+function createExitedProcess(code: number | null, signal: string | null = null) {
+  return {
+    on: (event: string, cb: (code: number | null, signal: string | null) => void) => {
+      if (event === "exit") {
+        queueMicrotask(() => cb(code, signal));
+      }
+      return undefined;
+    },
+  };
+}
